  {"id": "bil_calc_1", "tags": ["bil"], "difficulty": "hard", "type": "numeric", "prompt": "A 30 cm wire carries 2.00 A at right angles to a 0.40 T field. Calculate the force.", "answer": 0.24, "unitHint": "N", "explanation": "Convert length: l=0.30 m. F=BIl=0.40×2.00×0.30=0.24 N."},
  {"id": "bil_calc_2", "tags": ["bil"], "difficulty": "hard", "type": "numeric", "prompt": "A 15 cm wire carries 3.50 A at right angles to a 0.20 T field. Calculate the force.", "answer": 0.10500000000000001, "unitHint": "N", "explanation": "Convert length: l=0.15 m. F=BIl=0.20×3.50×0.15=0.105 N."},
  {"id": "bil_calc_3", "tags": ["bil"], "difficulty": "hard", "type": "numeric", "prompt": "A 5 cm wire carries 1.20 A at right angles to a 0.85 T field. Calculate the force.", "answer": 0.051000000000000004, "unitHint": "N", "explanation": "Convert length: l=0.05 m. F=BIl=0.85×1.20×0.05=0.051 N."},
  {"id": "bil_calc_4", "tags": ["bil"], "difficulty": "hard", "type": "numeric", "prompt": "A 20 cm wire carries 1.50 A at right angles to a 0.30 T field. Calculate the force.", "answer": 0.09, "unitHint": "N", "explanation": "Convert length: l=0.20 m. F=BIl=0.30×1.50×0.20=0.09 N."},
  {"id": "bil_calc_5", "tags": ["bil"], "difficulty": "hard", "type": "numeric", "prompt": "A 35 cm wire carries 0.80 A at right angles to a 0.50 T field. Calculate the force.", "answer": 0.13999999999999999, "unitHint": "N", "explanation": "Convert length: l=0.35 m. F=BIl=0.50×0.80×0.35=0.14 N."},
  {"id": "bil_calc_6", "tags": ["bil"], "difficulty": "hard", "type": "numeric", "prompt": "A 10 cm wire carries 4.00 A at right angles to a 0.12 T field. Calculate the force.", "answer": 0.048, "unitHint": "N", "explanation": "Convert length: l=0.10 m. F=BIl=0.12×4.00×0.10=0.048 N."},
  {"id": "bil_calc_7", "tags": ["bil"], "difficulty": "hard", "type": "numeric", "prompt": "A 18 cm wire carries 2.20 A at right angles to a 0.22 T field. Calculate the force.", "answer": 0.08712, "unitHint": "N", "explanation": "Convert length: l=0.18 m. F=BIl=0.22×2.20×0.18=0.0871 N."},
  {"id": "bil_calc_8", "tags": ["bil"], "difficulty": "hard", "type": "numeric", "prompt": "A 40 cm wire carries 0.60 A at right angles to a 0.75 T field. Calculate the force.", "answer": 0.18, "unitHint": "N", "explanation": "Convert length: l=0.40 m. F=BIl=0.75×0.60×0.40=0.18 N."},
  {"id": "bil_calc_9", "tags": ["bil"], "difficulty": "hard", "type": "numeric", "prompt": "A 12 cm wire carries 5.00 A at right angles to a 0.10 T field. Calculate the force.", "answer": 0.06, "unitHint": "N", "explanation": "Convert length: l=0.12 m. F=BIl=0.10×5.00×0.12=0.06 N."},
  {"id": "bil_calc_10", "tags": ["bil"], "difficulty": "hard", "type": "numeric", "prompt": "A 25 cm wire carries 1.10 A at right angles to a 0.65 T field. Calculate the force.", "answer": 0.17875000000000002, "unitHint": "N", "explanation": "Convert length: l=0.25 m. F=BIl=0.65×1.10×0.25=0.179 N."},
  {"id": "bil_find_B", "tags": ["bil"], "difficulty": "hard", "type": "numeric", "prompt": "A force of 0.36 N acts on a 0.40 m wire carrying 2.0 A at right angles. Calculate B.", "answer": 0.44999999999999996, "unitHint": "T", "explanation": "B=F/(Il)=0.36/(2.0×0.40)=0.45 T."},
  {"id": "bil_find_I", "tags": ["bil"], "difficulty": "hard", "type": "numeric", "prompt": "A 0.25 m wire is in a 0.60 T field at right angles. The force is 0.15 N. Calculate the current.", "answer": 1.0, "unitHint": "A", "explanation": "I=F/(Bl)=0.15/(0.60×0.25)=1.0 A."},
  {"id": "motor_rotate", "tags": ["motors", "motoreffect", "flhr"], "difficulty": "hard", "type": "short", "prompt": "Explain how the motor effect causes rotation of the coil in a d.c. motor.", "marks": 6, "markPoints": [{"any": ["forces on opposite sides", "opposite directions"]}, {"any": ["turning effect", "torque", "rotate"]}, {"any": ["commutator", "split-ring"]}, {"any": ["reverses current", "every half turn"]}, {"any": ["inertia", "momentum"]}, {"any": ["magnetic field", "field"]}], "explanation": "Opposite sides of the coil have forces in opposite directions, giving a turning effect. A split-ring commutator reverses the current every half-turn so the forces keep turning the coil; inertia carries it past vertical."},
  {"id": "motor_commutator", "tags": ["motors"], "difficulty": "med", "type": "mcq", "prompt": "The split-ring commutator:", "choices": ["reverses current every half turn", "makes field uniform", "increases resistance", "turns d.c. into a.c."], "answerIndex": 0, "explanation": "It reverses the current in the coil every half-turn."},
  {"id": "motor_speed", "tags": ["motors", "bil"], "difficulty": "med", "type": "mcq", "prompt": "Which change increases motor turning effect?", "choices": ["Decrease current", "Weaker magnet", "Increase current/field strength", "Make coil parallel to field"], "answerIndex": 2, "explanation": "Turning effect increases with current and field strength."},
  {"id": "piv_bil_combo_1", "tags": ["bil", "units"], "difficulty": "hard", "type": "numeric", "prompt": "A wire of length 0.20 m is at right angles to a magnetic field of 0.45 T. The circuit delivers 6 W at 12 V. Calculate the force on the wire.", "answer": 0.045000000000000005, "unitHint": "N", "explanation": "Step 1: P = IV ⇒ I = P/V = 6/12 = 0.5 A.\nStep 2: F = B I l = 0.45 × 0.5 × 0.20 = 0.045 N."},
  {"id": "piv_bil_combo_2", "tags": ["bil", "units"], "difficulty": "hard", "type": "numeric", "prompt": "A wire of length 0.35 m is at right angles to a magnetic field of 0.30 T. The circuit delivers 3.6 W at 9 V. Calculate the force on the wire.", "answer": 0.041999999999999996, "unitHint": "N", "explanation": "Step 1: P = IV ⇒ I = P/V = 3.6/9 = 0.4 A.\nStep 2: F = B I l = 0.30 × 0.4 × 0.35 = 0.042 N."},
  {"id": "piv_bil_combo_3", "tags": ["bil", "units"], "difficulty": "hard", "type": "numeric", "prompt": "A wire of length 0.10 m is at right angles to a magnetic field of 0.80 T. The circuit delivers 1.2 W at 6 V. Calculate the force on the wire.", "answer": 0.016, "unitHint": "N", "explanation": "Step 1: P = IV ⇒ I = P/V = 1.2/6 = 0.2 A.\nStep 2: F = B I l = 0.80 × 0.2 × 0.10 = 0.016 N."},
  {"id": "fields_rule_arrows", "tags": ["fields"], "difficulty": "easy", "type": "mcq", "prompt": "When drawing magnetic field lines, you should always include:", "choices": ["an arrow showing direction", "a label showing temperature", "a voltmeter symbol", "numbers on every line"], "answerIndex": 0, "explanation": "Field lines should have arrows to show direction."},
  {"id": "fields_rule_crossing", "tags": ["fields"], "difficulty": "easy", "type": "mcq", "prompt": "A student draws two magnetic field lines that cross. The problem is that crossing implies:", "choices": ["the field is strongest there", "two field directions at one point", "the magnet has no poles", "a current must be flowing"], "answerIndex": 1, "explanation": "At a point, the field has a single direction. Crossing would suggest two directions."},
  {"id": "fields_rule_touch", "tags": ["fields"], "difficulty": "med", "type": "mcq", "prompt": "In a correct field-line diagram around a bar magnet, field lines should:", "choices": ["stop in mid-air", "be continuous and meet the magnet", "cross at the poles", "all be equally spaced everywhere"], "answerIndex": 1, "explanation": "Lines should be continuous and meet the magnet (not broken)."},
  {"id": "fields_rule_spacing", "tags": ["fields"], "difficulty": "easy", "type": "mcq", "prompt": "In a field-line diagram, the magnetic field is strongest where the lines are:", "choices": ["furthest apart", "closest together", "perfectly horizontal", "drawn in red"], "answerIndex": 1, "explanation": "Closer lines indicate a stronger field."},
  {"id": "fields_rule_outside_dir", "tags": ["fields"], "difficulty": "med", "type": "mcq", "prompt": "Outside a bar magnet, the arrows on field lines point:", "choices": ["from S to N", "from N to S", "towards the nearest metal", "in circles around the magnet"], "answerIndex": 1, "explanation": "Outside the magnet, field lines go from north to south."},
  {"id": "fields_rule_direction_def", "tags": ["fields"], "difficulty": "med", "type": "mcq", "prompt": "The direction of a magnetic field at a point is defined as the direction of the force on a:", "choices": ["south pole", "north pole", "electron", "mass"], "answerIndex": 1, "explanation": "Field direction is defined by the force on a north pole."},
  {"id": "fields_rule_three_rules", "tags": ["fields"], "difficulty": "hard", "type": "short", "prompt": "Give three correct rules for drawing magnetic field lines around a bar magnet.", "marks": 3, "markPoints": [{"any": ["arrows", "direction", "n to s", "north to south"]}, {"any": ["not cross", "never cross"]}, {"any": ["continuous", "meet the magnet", "touch the magnet", "not broken"]}], "explanation": "Examples:\n• arrows show N→S outside the magnet\n• lines do not cross\n• lines are continuous and meet the magnet\n• closer spacing shows stronger field."},
  {"id": "induced_polarity", "tags": ["induced"], "difficulty": "hard", "type": "mcq", "prompt": "A permanent magnet’s N pole is near a piece of iron. The end of the iron nearest the N pole becomes:", "choices": ["N", "S", "no pole forms", "alternating"], "answerIndex": 1, "explanation": "Induced magnetism makes the nearest end the opposite pole (S), giving attraction."},
  {"id": "induced_repulsion", "tags": ["induced"], "difficulty": "med", "type": "mcq", "prompt": "Induced magnetism always causes a force of:", "choices": ["repulsion", "attraction", "zero", "friction"], "answerIndex": 1, "explanation": "Induced magnets are attracted to the magnet causing the induction."},
  {"id": "induced_material", "tags": ["induced"], "difficulty": "easy", "type": "mcq", "prompt": "Which material is most likely to become an induced magnet?", "choices": ["iron", "plastic", "glass", "wood"], "answerIndex": 0, "explanation": "Iron is magnetic and becomes induced in a field."},
  {"id": "perm_definition", "tags": ["induced", "poles"], "difficulty": "med", "type": "mcq", "prompt": "Which statement best describes a permanent magnet?", "choices": ["Only magnetic in a field", "Produces its own magnetic field", "Always loses magnetism quickly", "Only attracts unlike poles"], "answerIndex": 1, "explanation": "A permanent magnet produces its own magnetic field."},
  {"id": "induced_vs_perm_short", "tags": ["induced"], "difficulty": "hard", "type": "short", "prompt": "In one sentence each, describe (i) a permanent magnet, and (ii) an induced magnet.", "marks": 4, "markPoints": [{"any": ["permanent", "own magnetic field", "produces its own"]}, {"any": ["induced", "becomes a magnet", "in a magnetic field"]}, {"any": ["temporary", "loses", "quickly when removed"]}, {"any": ["attraction", "always attracts"]}], "explanation": "Permanent magnet: produces its own magnetic field.\nInduced magnet: becomes magnetised in a magnetic field, is temporary, and gives attraction."},
  {"id": "induced_force_reason", "tags": ["induced"], "difficulty": "med", "type": "mcq", "prompt": "A magnet always attracts a magnetic material because the material becomes:", "choices": ["electrically charged", "an induced magnet", "a permanent magnet", "a solenoid"], "answerIndex": 1, "explanation": "The material becomes an induced magnet, so the force is attraction."},
  {"id": "ppq_field_arrows", "tags": ["fields", "plotting"], "difficulty": "easy", "type": "mcq", "prompt": "A student draws a field pattern around a bar magnet but forgets arrowheads. What information are the arrowheads supposed to show?", "choices": ["The strength of the field", "The direction of the magnetic field (N→S outside)", "The mass of the magnet", "The temperature of the magnet"], "answerIndex": 1, "explanation": "Arrowheads show the direction of the field (direction of force on a north pole). Outside a bar magnet: N → S."},
  {"id": "ppq_field_strength_evidence", "tags": ["fields"], "difficulty": "med", "type": "mcq", "prompt": "In a diagram of field lines, how can you tell the field is not the same strength everywhere?", "choices": ["All lines are straight", "The spacing between lines changes from place to place", "There are arrows", "The magnet is labelled"], "answerIndex": 1, "explanation": "Changing spacing shows changing field strength (closer = stronger)."},
  {"id": "ppq_draw_rules_markscheme", "tags": ["fields"], "difficulty": "hard", "type": "short", "prompt": "A bar magnet field-line diagram is marked out of 3. Give three marking-point rules that would earn marks.", "marks": 3, "markPoints": [{"any": ["pattern", "correct shape", "loops around"]}, {"any": ["arrows", "direction", "n to s", "north to south"]}, {"any": ["not cross", "never cross", "lines do not cross", "continuous", "touch the magnet"]}], "explanation": "Examples of marking points: correct overall pattern; arrows showing N→S outside; lines do not cross and are continuous/meet the magnet; closer spacing near poles."},
  {"id": "ppq_attraction_inference", "tags": ["poles"], "difficulty": "easy", "type": "mcq", "prompt": "Two bar magnets are brought close and they ATTRACT. What can you conclude about the facing poles?", "choices": ["They must be like poles", "They must be opposite poles", "You cannot tell anything", "Both must be north"], "answerIndex": 1, "explanation": "Attraction between magnets occurs between unlike poles."},
  {"id": "ppq_test_perm_magnet", "tags": ["induced", "poles"], "difficulty": "hard", "type": "short", "prompt": "You have an iron bar. Describe how to test whether it is a PERMANENT magnet using a known permanent magnet.", "marks": 3, "markPoints": [{"any": ["bring same end", "one end", "same end of iron"]}, {"any": ["to both poles", "each pole", "north and south"]}, {"any": ["repel", "repulsion proves permanent", "if repels"]}], "explanation": "Bring the same end of the bar to the N pole and then the S pole of a known magnet. If you ever get REPULSION, the bar is a permanent magnet. If it’s attracted to both poles, it’s just induced magnetism."},
  {"id": "ppq_compass_same_direction", "tags": ["compass"], "difficulty": "med", "type": "short", "prompt": "Several plotting compasses on a desk all point the same way when there is no nearby magnet. Explain why.", "marks": 2, "markPoints": [{"any": ["earth", "earth's magnetic field"]}, {"any": ["align", "line up", "points north"]}], "explanation": "They align with Earth’s magnetic field, so they all point in the same direction (towards north)."},
  {"id": "ppq_earth_evidence", "tags": ["compass"], "difficulty": "med", "type": "mcq", "prompt": "A compass provides evidence Earth has a magnetic field because the needle:", "choices": ["always points uphill", "always points the same way (north) because it aligns with Earth’s field", "is attracted by gravity", "is made of aluminium"], "answerIndex": 1, "explanation": "A compass needle is a magnet; it aligns with Earth’s magnetic field."},
  {"id": "ppq_wire_field_shape", "tags": ["wirefield"], "difficulty": "easy", "type": "mcq", "prompt": "When a current flows in a straight wire, the magnetic field lines around it are:", "choices": ["circular", "square", "triangular", "straight lines from + to −"], "answerIndex": 0, "explanation": "Field lines around a straight wire are concentric circles."},
  {"id": "ppq_reverse_current_compass", "tags": ["wirefield"], "difficulty": "med", "type": "mcq", "prompt": "Compasses around a straight wire change direction when current flows. If the current is reversed, the compass needles will:", "choices": ["stay the same", "reverse direction", "point north again", "stop moving"], "answerIndex": 1, "explanation": "Reversing the current reverses the magnetic field direction, so the compass directions reverse."},
  {"id": "ppq_solenoid_inside_uniform", "tags": ["solenoid"], "difficulty": "med", "type": "mcq", "prompt": "Inside a solenoid carrying current, the magnetic field is best described as:", "choices": ["strong and uniform", "weak and random", "zero", "only at the ends"], "answerIndex": 0, "explanation": "Inside a solenoid the field is strong and approximately uniform."},
  {"id": "ppq_solenoid_field_features", "tags": ["solenoid", "plotting"], "difficulty": "hard", "type": "short", "prompt": "When drawing the magnetic field around a solenoid, give three features you should include for full marks.", "marks": 3, "markPoints": [{"any": ["uniform", "straight", "equally spaced", "inside"]}, {"any": ["curving around", "loops", "outside"]}, {"any": ["arrows", "n to s", "north to south"]}], "explanation": "Inside: straight, evenly spaced (uniform) lines. Outside: curved lines forming loops. Add arrows showing N→S outside."},
  {"id": "ppq_identify_three_blocks", "tags": ["induced", "poles"], "difficulty": "hard", "type": "short", "prompt": "Three unlabelled blocks are: a permanent magnet, iron, and aluminium. Describe how to identify each using a known permanent magnet.", "marks": 4, "markPoints": [{"any": ["repel", "repulsion"]}, {"any": ["permanent magnet", "the one that repels"]}, {"any": ["iron", "attracted"]}, {"any": ["aluminium", "no effect", "not attracted"]}], "explanation": "Bring a known magnet near each block. Any block that can REPEL must be the permanent magnet. A block that is attracted but never repels is iron (induced magnetism). A block with no effect is aluminium."},
  {"id": "ppq_control_variable_current", "tags": ["plotting", "solenoid"], "difficulty": "easy", "type": "mcq", "prompt": "In an experiment measuring how force changes with distance from an electromagnet, the current is kept the same each time. The current is the:", "choices": ["independent variable", "dependent variable", "control variable", "random variable"], "answerIndex": 2, "explanation": "If it’s kept the same, it’s a control variable."},
  {"id": "ppq_distance_force_trend", "tags": ["solenoid"], "difficulty": "easy", "type": "mcq", "prompt": "A paperclip is held by an electromagnet. If the distance between them increases, the magnetic force on the paperclip will usually:", "choices": ["increase", "decrease", "stay the same", "reverse direction"], "answerIndex": 1, "explanation": "Field strength decreases with distance, so the force decreases."},
  {"id": "ppq_electromagnet_crane", "tags": ["solenoid"], "difficulty": "hard", "type": "short", "prompt": "Explain how an electromagnet on a toy crane can pick up and release blocks.", "marks": 6, "markPoints": [{"any": ["complete circuit", "switch on", "current"]}, {"any": ["coil", "solenoid"]}, {"any": ["magnetic field", "produced"]}, {"any": ["iron core", "becomes magnetised"]}, {"any": ["attract", "pick up"]}, {"any": ["switch off", "current off", "demagnetise", "release"]}], "explanation": "Switch on → current in coil → magnetic field → iron core becomes magnetised → attracts block. Move crane. Switch off → current stops → core demagnetises → block released."},
  {"id": "ppq_reverse_force_two_ways", "tags": ["motoreffect", "flhr"], "difficulty": "med", "type": "short", "prompt": "Give TWO ways to reverse the direction of the force on a current‑carrying wire in a magnetic field.", "marks": 2, "markPoints": [{"any": ["reverse current", "swap connections"]}, {"any": ["reverse magnetic field", "swap poles", "turn magnet around"]}], "explanation": "Reverse the current OR reverse the magnetic field direction (swap poles)."},
  {"id": "ppq_balance_reading_increase", "tags": ["motoreffect", "bil"], "difficulty": "hard", "type": "short", "prompt": "A magnet sits on a balance. A wire above it carries current and experiences an upward force. Explain why the balance reading increases.", "marks": 4, "markPoints": [{"any": ["motor effect", "force on wire"]}, {"any": ["equal and opposite", "newton's third"]}, {"any": ["force on magnet", "downwards"]}, {"any": ["balance reading increases", "extra downward force"]}], "explanation": "Motor effect gives a force on the wire. By Newton’s 3rd law, the wire/magnetic field exerts an equal and opposite force on the magnet. If the wire is pushed up, the magnet is pushed down more, increasing the balance reading."},
  {"id": "ppq_graph_force_current", "tags": ["bil", "motoreffect"], "difficulty": "med", "type": "mcq", "prompt": "For a fixed magnet and fixed wire length, the motor-effect force on the wire is proportional to the current. The graph of force (y) vs current (x) is:", "choices": ["a straight line through the origin", "a straight line not through origin", "a curve", "a horizontal line"], "answerIndex": 0, "explanation": "F = B I l, so F ∝ I (line through origin)."},
  {"id": "ppq_current_from_mT", "tags": ["bil"], "difficulty": "hard", "type": "numeric", "prompt": "A wire of length 0.050 m experiences a force of 0.072 N in a field of 360 mT. Calculate the current.", "answer": 4.0, "unitHint": "A", "explanation": "Convert 360 mT = 0.360 T. Then I = F/(B l) = 0.072/(0.360×0.050) = 4.0 A."},
  {"id": "ppq_B_from_mm", "tags": ["bil"], "difficulty": "hard", "type": "numeric", "prompt": "A length of wire in the field is 120 mm. Current is 4.0 A. Force on the wire is 0.36 N. Calculate magnetic flux density B (give unit).", "answer": 0.75, "unitHint": "T", "explanation": "Convert 120 mm = 0.120 m. B = F/(I l) = 0.36/(4.0×0.120) = 0.75 T."},
  {"id": "ppq_B_calc_variant1", "tags": ["bil"], "difficulty": "hard", "type": "numeric", "prompt": "A wire of length 0.060 m carries 1.50 A at right angles to the field. The force is 0.180 N. Calculate B.", "answer": 2.0, "unitHint": "T", "explanation": "Use F=BIl ⇒ B=F/(Il) = 0.180/(1.50×0.060) = 2 T."},
  {"id": "ppq_B_calc_variant2", "tags": ["bil"], "difficulty": "hard", "type": "numeric", "prompt": "A wire of length 0.048 m carries 0.80 A at right angles to the field. The force is 0.090 N. Calculate B.", "answer": 2.3437499999999996, "unitHint": "T", "explanation": "Use F=BIl ⇒ B=F/(Il) = 0.090/(0.80×0.048) = 2.34 T."},
  {"id": "ppq_B_from_balance_zero", "tags": ["bil", "motoreffect"], "difficulty": "hard", "type": "numeric", "prompt": "A horizontal copper rod has mass 4.0×10⁻⁴ kg and length 0.070 m in the magnetic field. When current is 1.12 A, the resultant force on the rod is 0 N. Calculate B. (g = 9.8 N/kg)", "answer": 0.05, "unitHint": "T", "explanation": "Resultant 0 means magnetic force = weight.\nW = mg = 9.8×4.0×10⁻⁴ = 3.92×10⁻³ N.\nB = F/(I l) = 3.92×10⁻³ /(1.12×0.070) = 0.05 T."},
  {"id": "ppq_which_metals_magnetic", "tags": ["induced"], "difficulty": "med", "type": "mcq", "prompt": "A student tests five metals with a magnet: iron, steel, aluminium, copper, tin. Which are attracted?", "choices": ["iron and steel only", "all five", "aluminium and copper", "iron only"], "answerIndex": 0, "explanation": "Iron and steel are magnetic; aluminium, copper and tin are not."},
  {"id": "ppq_paperclip_south_pole", "tags": ["induced"], "difficulty": "hard", "type": "short", "prompt": "A paperclip is attracted to the NORTH pole of a permanent magnet. The paperclip is then removed and brought near the SOUTH pole. What happens and why?", "marks": 2, "markPoints": [{"any": ["attracted"]}, {"any": ["induced magnetism", "becomes an induced magnet", "temporary magnet"]}], "explanation": "It is still attracted. The paperclip becomes an induced magnet, so it is attracted to either pole."},
  {"id": "ppq_max_force_paperclips", "tags": ["induced", "units"], "difficulty": "hard", "type": "numeric", "prompt": "A magnet can hold 20 paperclips. Each paperclip has mass 1.0 g. Calculate the maximum magnetic force (g = 9.8 N/kg).", "answer": 0.19600000000000004, "unitHint": "N", "explanation": "Convert 1.0 g = 0.0010 kg.\nWeight of one = mg = 0.0010×9.8 = 0.0098 N.\nTotal for 20 = 0.0098×20 = 0.196 N."},
  {"id": "ppq_ring_float", "tags": ["poles"], "difficulty": "med", "type": "mcq", "prompt": "A ring magnet appears to float above another ring magnet on a rod. The most likely reason is:", "choices": ["unlike poles facing (attraction)", "like poles facing (repulsion)", "no magnetic field", "induced magnetism"], "answerIndex": 1, "explanation": "Floating happens when like poles face and repel."},
  {"id": "ppq_ring_flip", "tags": ["poles"], "difficulty": "med", "type": "mcq", "prompt": "If the floating ring magnet is turned upside down, it will most likely:", "choices": ["still float the same", "be attracted and move towards the other magnet", "lose magnetism instantly", "spin forever"], "answerIndex": 1, "explanation": "Flipping swaps which pole faces, so like → unlike; attraction occurs."},
  {"id": "ppq_flhr_labels", "tags": ["flhr"], "difficulty": "med", "type": "mcq", "prompt": "Fleming’s left-hand rule: which finger shows the direction of the magnetic field (N→S)?", "choices": ["thumb", "first/index finger", "second/middle finger", "little finger"], "answerIndex": 1, "explanation": "First (index) finger shows magnetic field direction."},
  {"id": "ppq_flhr_labels_force", "tags": ["flhr"], "difficulty": "easy", "type": "mcq", "prompt": "In Fleming’s left-hand rule (FBI), the thumb represents:", "choices": ["field", "current", "force", "flux density"], "answerIndex": 2, "explanation": "Thumb = Force, First finger = Field, Second finger = Current."},
  {"id": "ppq_motor_rotation_core", "tags": ["motors", "motoreffect", "flhr"], "difficulty": "hard", "type": "short", "prompt": "Explain why the coil in a simple d.c. motor rotates when current flows.", "marks": 4, "markPoints": [{"any": ["current produces magnetic field", "magnetic field around coil"]}, {"any": ["forces on opposite sides", "opposite directions"]}, {"any": ["turning effect", "rotates", "torque"]}, {"any": ["split ring", "commutator", "reverses current each half turn", "keeps direction"]}], "explanation": "Current in coil produces a field. In the external field, forces act on opposite sides in opposite directions, giving a turning effect. Split-ring commutator reverses current every half-turn so the turning continues."},
  {"id": "ppq_motor_speed_increase", "tags": ["motors"], "difficulty": "med", "type": "short", "prompt": "Give one change to increase the speed of rotation of a simple motor and explain why it works.", "marks": 2, "markPoints": [{"any": ["increase current", "stronger magnet", "more turns", "move magnets closer"]}, {"any": ["increase force", "greater turning effect", "increase torque"]}], "explanation": "Increasing current/field strength/turns increases the motor-effect force, giving a larger turning effect so the motor spins faster."}
